 {"id":"bd-3fc","title":"Epic: Testing & Conformance Infrastructure","description":"Comprehensive testing infrastructure: unit tests for every module, integration tests for ring boundaries, E2E tests for full render pipeline, property-based tests (section 6.12), deterministic replay via FrankenLab, golden frame checksums for 47+ test scenarios, terminal emulator compatibility matrix (5 emulators), conformance harness, fuzz testing for ANSI parser, performance regression gates with slo.yaml enforcement.","status":"open","priority":0,"issue_type":"epic","created_at":"2026-02-13T17:58:00.029731605Z","created_by":"ubuntu","updated_at":"2026-02-13T17:58:00.029731605Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["conformance","epic","quality","testing"]}
 {"id":"bd-3fc.1","title":"Golden frame checksum infrastructure (BLAKE3)","description":"Infrastructure for golden-frame testing: capture terminal output as byte array, compute BLAKE3 hash, compare against stored golden checksums. 47+ test scenarios covering: all widget types, all terminal emulators, resize, animations, edge cases. Update workflow: cargo test -- --update-golden. Storage: golden checksums in tests/golden/ directory. TRACING: span 'golden.compare' with fields: scenario_name, computed_hash, expected_hash, match. LOG: INFO for golden update, ERROR for mismatch. METRICS: counter golden_tests_run_total, counter golden_mismatches_total.","status":"closed","priority":0,"issue_type":"feature","created_at":"2026-02-13T18:05:11.836995812Z","created_by":"ubuntu","updated_at":"2026-02-14T04:24:47.297076015Z","closed_at":"2026-02-14T04:24:47.297056639Z","close_reason":"Already implemented: BLAKE3 golden frame infrastructure in ftui-harness (golden.rs, golden_resize.rs, golden_checksums.rs, checksum files)","source_repo":".","compaction_level":0,"original_size":0,"labels":["blake3","conformance","golden","testing"],"dependencies":[{"issue_id":"bd-3fc.1","depends_on_id":"bd-1q5.6","type":"blocks","created_at":"2026-02-24T21:26:01Z","created_by":"import","metadata":"{}","thread_id":""},{"issue_id":"bd-3fc.1","depends_on_id":"bd-3fc","type":"parent-child","created_at":"2026-02-24T21:26:01Z","created_by":"import","metadata":"{}","thread_id":""}]}
